238	              ...(resultSeed != null && { seed: resultSeed }),
239	              ...(resultStartTime != null && { start_time: resultStartTime }),
240	              ...(resultEndTime != null && { end_time: resultEndTime }),
241	              ...(resultDuration != null && { duration: resultDuration }),
242	              ...(submit.value.cost != null && { cost: submit.value.cost }),
243	              ...(submit.value.input_mp != null && {
244	                inputMegapixels: submit.value.input_mp,
245	              }),
246	              ...(submit.value.output_mp != null && {
247	                outputMegapixels: submit.value.output_mp,
248	              }),
249	            },
250	          ],
251	        },
252	      },
253	      response: {
254	        modelId: this.modelId,
255	        timestamp: currentDate,
256	        headers: responseHeaders,
257	      },
258	    };
259	  }
260	
261	  private async pollForImageUrl({
262	    pollUrl,
263	    requestId,
264	    headers,
265	    abortSignal,
266	    pollOverrides,
267	  }: {
268	    pollUrl: string;
269	    requestId: string;
270	    headers: Record<string, string | undefined>;
271	    abortSignal: AbortSignal | undefined;
272	    pollOverrides?: {
273	      pollIntervalMillis?: number;
274	      pollTimeoutMillis?: number;
275	    };
276	  }): Promise<{
277	    imageUrl: string;
278	    seed?: number;
279	    start_time?: number;
280	    end_time?: number;
281	    duration?: number;
282	  }> {
283	    const pollIntervalMillis =
284	      pollOverrides?.pollIntervalMillis ??
285	      this.config.pollIntervalMillis ??
286	      DEFAULT_POLL_INTERVAL_MILLIS;
287	    const pollTimeoutMillis =
288	      pollOverrides?.pollTimeoutMillis ??
289	      this.config.pollTimeoutMillis ??
290	      DEFAULT_POLL_TIMEOUT_MILLIS;
291	    const maxPollAttempts = Math.ceil(
292	      pollTimeoutMillis / Math.max(1, pollIntervalMillis),
293	    );
294	
295	    const url = new URL(pollUrl);
296	    if (!url.searchParams.has('id')) {
297	      url.searchParams.set('id', requestId);
298	    }
299	
300	    for (let i = 0; i < maxPollAttempts; i++) {
301	      const { value } = await getFromApi({
302	        url: url.toString(),
303	        headers,
304	        failedResponseHandler: bflFailedResponseHandler,
305	        successfulResponseHandler: createJsonResponseHandler(bflPollSchema),
